import{_ as e,c as o,o as s,ah as t}from"./chunks/framework.C-x9UAyH.js";const p=JSON.parse('{"title":"Computador vs Máquinas virtuales","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/computador_maq_virtuales.md","filePath":"aws/computador_maq_virtuales.md","lastUpdated":1760459112000}'),r={name:"aws/computador_maq_virtuales.md"};function n(d,a,i,l,c,u){return s(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="computador-vs-maquinas-virtuales" tabindex="-1">Computador vs Máquinas virtuales <a class="header-anchor" href="#computador-vs-maquinas-virtuales" aria-label="Permalink to &quot;Computador vs Máquinas virtuales&quot;">​</a></h1><h2 id="componentes-de-un-pc" tabindex="-1">Componentes de un PC <a class="header-anchor" href="#componentes-de-un-pc" aria-label="Permalink to &quot;Componentes de un PC&quot;">​</a></h2><ul><li><p>Hardware:Componentes físicos de un computador, como la CPU, memoria RAM y disco duro.</p></li><li><p>Software: Programas y aplicaciones informáticas que brindan funcionalidades al computador.</p></li></ul><h3 id="ram" tabindex="-1">RAM <a class="header-anchor" href="#ram" aria-label="Permalink to &quot;RAM&quot;">​</a></h3><p>Memoria de Acceso Aleatorio.</p><p>Tipo de memoria temporal que almacena datos utilizados por el procesador en tiempo real.</p><h3 id="disco-duro" tabindex="-1">Disco Duro <a class="header-anchor" href="#disco-duro" aria-label="Permalink to &quot;Disco Duro&quot;">​</a></h3><p>Es una unidad de hardware que se usa para almacenar contenido (Juegos, programas, Office, etc.).</p><h4 id="ssd-vs-disco-duro" tabindex="-1">SSD vs. Disco Duro <a class="header-anchor" href="#ssd-vs-disco-duro" aria-label="Permalink to &quot;SSD vs. Disco Duro&quot;">​</a></h4><p>Las unidades de estado sólido (SSD) y las unidades de disco duro (HDD) son dispositivos (Hardware) de almacenamiento de datos. Los SSD almacenan datos en la memoria flash, mientras que las HDD almacenan datos en discos magnéticos. Las SSD son una tecnología más reciente que utiliza las propiedades físicas y químicas del silicio para ofrecer más volumen de almacenamiento, velocidad y eficiencia. Sin embargo, las HDD son una opción rentable si necesita un acceso poco frecuente a los datos en bloques de 1 MB o más a la vez.</p><table tabindex="0"><thead><tr><th><strong>Criterios</strong></th><th><strong>SSD</strong></th><th><strong>HDD</strong></th></tr></thead><tbody><tr><td><strong>Qué significa</strong></td><td>SSD son las siglas de <em>Solid State Drive</em> (unidad de estado sólido).</td><td>HDD son las siglas de <em>Hard Disk Drive</em> (unidad de disco duro).</td></tr><tr><td><strong>Funcionamiento</strong></td><td>Las SSD almacenan datos en circuitos electrónicos.</td><td>Las HDD almacenan datos en placas magnéticas que se mueven mecánicamente.</td></tr><tr><td><strong>Proceso de lectura</strong></td><td>Un controlador de SSD encuentra la dirección correcta y lee sus cargas.</td><td>Un controlador de E/S de HDD envía una señal que mueve el brazo de accionamiento. A continuación, el cabezal de lectura/escritura lee los cargos.</td></tr><tr><td><strong>Proceso de escritura</strong></td><td>Una SSD copia los datos en un bloque nuevo y, a continuación, borra el bloque anterior. Luego escribe lo nuevo en el bloque anterior cambiando sus cargas.</td><td>Una HDD mueve el cabezal de lectura/escritura a la ubicación disponible más cercana. Luego escribe datos cambiando la carga de bits en esa área.</td></tr><tr><td><strong>Rendimiento</strong></td><td>Las SSD son más rápidas. Son silenciosas y funcionan mejor.</td><td>Las HDD son más lentas ya que sus discos tienen que moverse. Liberan más calor y son ruidosas.</td></tr><tr><td><strong>Costo</strong></td><td>Las SSD son más costosas.</td><td>Las HDD son menos costosas y los volúmenes de almacenamiento más grandes son populares en el mercado.</td></tr><tr><td><strong>Durabilidad</strong></td><td>Las SSD son eléctricas, lo que las hace menos propensas a sufrir daños.</td><td>Las HDD tienen piezas mecánicas móviles que las hacen comparativamente menos duraderas.</td></tr></tbody></table><h3 id="procesador" tabindex="-1">Procesador <a class="header-anchor" href="#procesador" aria-label="Permalink to &quot;Procesador&quot;">​</a></h3><p>Unidad central de procesamiento que ejecuta instrucciones y determina la velocidad de un computador.</p><ul><li>Núcleos del procesador:</li></ul><p>Unidades individuales dentro de la CPU que manejan tareas específicas, permitiendo la multitarea.</p><ul><li>*Velocidad del reloj del procesador:</li></ul><p>Medida en GHz, indica la rapidez con la que la CPU interpreta instrucciones.</p><h2 id="maquina-virtual" tabindex="-1">Máquina Virtual <a class="header-anchor" href="#maquina-virtual" aria-label="Permalink to &quot;Máquina Virtual&quot;">​</a></h2><p>Versiones digitales de computadoras físicas que ejecutan programas y sistemas operativos, almacenar datos, conectarse a redes y realizar otras funciones informática de manera independiente.</p><p>Las funciones más comunes de las máquinas virtuales son:</p><table tabindex="0"><thead><tr><th>Crea entornos de desarrollo y pruebas</th><th>Las máquinas virtuales pueden usarse como entornos aislados de desarrollo y pruebas que incluyen todas las funciones, pero no tienen un impacto en el resto de la infraestructura.</th></tr></thead><tbody><tr><td>Brinda asistencia a desarrolladores</td><td>Es posible activar o desactivar, migrar y adaptar las máquinas virtuales para gozar de la máxima flexibilidad para el desarrollo.</td></tr><tr><td>Crea entornos híbridos</td><td>Las máquinas virtuales ofrecen las bases para crear un entorno en la nube respaldado por otro entorno on-premise, lo que te proporciona una gran flexibilidad sin tener que abandonar los sistemas antiguos.</td></tr></tbody></table>',21)])])}const h=e(r,[["render",n]]);export{p as __pageData,h as default};
